const cleanResp = $input.first().json;
const config = $node["Set Config"].json;
const details = Array.isArray(cleanResp.details) ? cleanResp.details : [];

if (details.length === 0) {
  throw new Error('clean-nested-dataset 未返回任何可转换目录');
}

return details
  .filter((detail) => detail.labeled_images > 0)
  .map((detail) => ({
    json: {
      api_base_url: config.api_base_url,
      dataset_dir: detail.output_dir,
      source_dir: detail.source_dir,
      labeled_images: detail.labeled_images,
      clean_output_dir: config.clean_output_dir,
      aggregated_output_dir: config.aggregated_output_dir,
      images_dir_name: config.images_dir_name,
      xmls_dir_name: config.xmls_dir_name,
      labels_dir_name: config.labels_dir_name,
      include_difficult: config.include_difficult,
      overwrite: config.overwrite,
    },
  }));

